import { QueryClient, QueryClientProvider } from "@tanstack/react-query";
import {
  createTRPCClient,
  httpBatchStreamLink,
  isNonJsonSerializable,
  splitLink,
} from "@trpc/client";
import { useState } from "react";
import superjson from "superjson";

import type { AppRouter } from "@/server/routers/app";

const queryClient = new QueryClient();

const trpcClient = createTRPCClient<AppRouter>({
  links: [
    splitLink({
      condition(op) {
        return isNonJsonSerializable(op.input);
      },
      true: httpBatchStreamLink({
        transformer: superjson,
        url: getBaseUrl() + "/api/trpc",
      }),
      false: httpBatchStreamLink({
        transformer: superjson,
        url: getBaseUrl() + "/api/trpc",
      }),
    }),
  ],
});

function getBaseUrl() {
  if (typeof window !== "undefined") {
    return window.location.origin;
  }

  return "http://localhost:3000";
}

export function ChatClient() {
  const [message, setMessage] = useState("");
  const [response, setResponse] = useState("");
  const [isStreaming, setIsStreaming] = useState(false);

  const handleSubmit = async (event: React.FormEvent<HTMLFormElement>) => {
    event.preventDefault();

    setResponse("");
    setIsStreaming(true);

    try {
      const stream = await trpcClient.chat.query(message);

      for await (const character of stream) {
        setResponse((current) => current + character);
      }
    } finally {
      setIsStreaming(false);
    }
  };

  return (
    <QueryClientProvider client={queryClient}>
      <main className="flex min-h-screen items-center justify-center bg-slate-950 px-6 py-12 text-slate-50">
        <div className="w-full max-w-2xl rounded-2xl border border-slate-800 bg-slate-900 p-8 shadow-2xl shadow-slate-950/4

